customCss:
/* Dyslexia readability tweaks */
:root {
  --dyslexia-word-spacing: 3px;
  --dyslexia-letter-spacing: 0.25px;
  --dyslexia-line-height: 2;
}

/* Apply to all text */
body, textarea, input, button, select, .messageContent, .markup, .textArea {
  word-spacing: var(--dyslexia-word-spacing) !important;
  letter-spacing: var(--dyslexia-letter-spacing) !important;
}

/* Message line height */
.messageContent, .contents, [class*="messageContent"], [class*="contents"] {
  line-height: var(--dyslexia-line-height) !important;
}

/* Timestamps smaller to reduce clutter */
.timestamp, time, [class*="timestamp"] {
  font-size: 0.9rem !important;
}

/* Slight background contrast for better focus */
.textArea {
  background-color: rgba(0, 0, 0, 0.25) !important;
}
